/* Suggested markup: <div class="uiwiki-keyboard-map-navigator" tabindex="0"><span>Keyboard Map Navigator</span></div> */
.uiwiki-keyboard-map-navigator {
  display: grid;
  place-items: center;
  min-height: 11rem;
  padding: 1.25rem;
  border: 1px solid #ececee;
  border-radius: 22px;
  background: #ffffff;
  color: #111111;
  font: 700 1rem/1.2 Inter, system-ui, sans-serif;
  box-shadow: 0 2px 16px rgba(0, 0, 0, 0.04);
  transition: transform 240ms cubic-bezier(.22, 1, .36, 1), box-shadow 240ms ease;
}
.uiwiki-keyboard-map-navigator > span {
  padding: .75rem 1rem;
  border-radius: 999px;
  background: #d8f34e;
  animation: keyboard_map_navigator 1.8s ease-in-out infinite alternate;
}
.uiwiki-keyboard-map-navigator:hover,
.uiwiki-keyboard-map-navigator:focus-visible {
  transform: translateY(-3px);
  box-shadow: 0 10px 28px rgba(0, 0, 0, 0.08);
}
@keyframes keyboard_map_navigator {
  from { transform: translateY(0) scale(1); }
  to { transform: translateY(-4px) scale(1.025); }
}
@media (prefers-reduced-motion: reduce) {
  .uiwiki-keyboard-map-navigator, .uiwiki-keyboard-map-navigator > span { animation: none; transition: none; }
}
